arguments.file_text:
@page "/settings"
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<div class="settings-layout">
    <nav class="settings-sidebar">
        <h5 class="sidebar-title">Settings</h5>
        <ul class="nav flex-column">
            @foreach (var section in _sections)
            {
                <li class="nav-item">
                    <button class="nav-link @(ActiveSection == section.Key ? "active" : "")"
                            @onclick="() => ActiveSection = section.Key">
                        <span class="section-icon">@section.Icon</span>
                        @section.Label
                    </button>
                </li>
            }
        </ul>
    </nav>

    <div class="settings-content">
        @switch (ActiveSection)
        {
            case "profile":
                <SettingsProfile />
                break;
            case "notifications":
                <SettingsNotifications />
                break;
            case "security":
                <SettingsSecurity />
                break;
            case "appearance":
                <SettingsAppearance />
                break;
        }
    </div>
</div>

@code {
    private string ActiveSection { get; set; } = "profile";

    private readonly record struct SectionDef(string Key, string Label, string Icon);

    private static readonly SectionDef[] _sections =
    [
        new("profile", "Profile", "👤"),
        new("notifications", "Notifications", "🔔"),
        new("security", "Security", "🔒"),
        new("appearance", "Appearance", "🎨"),
    ];
}

.settings-layout {
    display: flex;
    min-height: 75vh;
    gap: 0;
    border: 1px solid #dee2e6;
    border-radius: 0.5rem;
    overflow: hidden;
    background: #fff;
}

.settings-sidebar {
    width: 220px;
    min-width: 220px;
    background: #f8f9fa;
    border-right: 1px solid #dee2e6;
    padding: 1.25rem 0;
}

.sidebar-title {
    padding: 0 1.25rem 0.75rem;
    margin: 0;
    font-weight: 600;
    color: #495057;
    font-size: 0.85rem;
    text-transform: uppercase;
    letter-spacing: 0.05em;
}

.settings-sidebar .nav-link {
    display: flex;
    align-items: center;
    gap: 0.6rem;
    padding: 0.6rem 1.25rem;
    color: #495057;
    border: none;
    background: none;
    width: 100%;
    text-align: left;
    font-size: 0.95rem;
    cursor: pointer;
    border-left: 3px solid transparent;
    transition: background 0.15s, border-color 0.15s;
}

.settings-sidebar .nav-link:hover {
    background: #e9ecef;
}

.settings-sidebar .nav-link.active {
    background: #e7f1ff;
    color: #0d6efd;
    font-weight: 600;
    border-left-color: #0d6efd;
}

.section-icon {
    font-size: 1.1rem;
}

.settings-content {
    flex: 1;
    padding: 1.5rem 2rem;
    overflow-y: auto;
}

/* Toast notification */
.settings-toast {
    position: fixed;
    bottom: 1.5rem;
    right: 1.5rem;
    z-index: 1055;
    min-width: 260px;
    animation: toast-slide-in 0.3s ease;
}

@keyframes toast-slide-in {
    from {
        opacity: 0;
        transform: translateY(1rem);
    }
    to {
        opacity: 1;
        transform: translateY(0);
    }
}

/* Shared section styles */
::deep .section-header {
    margin-bottom: 1.5rem;
    padding-bottom: 0.75rem;
    border-bottom: 1px solid #dee2e6;
}

::deep .section-header h3 {
    margin: 0;
    font-size: 1.35rem;
    font-weight: 600;
}

::deep .section-header p {
    margin: 0.25rem 0 0;
    color: #6c757d;
    font-size: 0.9rem;
}

::deep .field-group {
    margin-bottom: 1rem;
}

::deep .field-group label {
    font-weight: 500;
    margin-bottom: 0.35rem;
    display: block;
    font-size: 0.9rem;
}

::deep .btn-actions {
    display: flex;
    gap: 0.75rem;
    margin-top: 1.5rem;
}

@using sv_828111b90db542599b2777ad48041c1b.Services
@inject ISettingsService SettingsService

@if (_loading)
{
    <div class="text-center py-5"><div class="spinner-border text-primary" role="status"></div></div>
}
else if (_profile is not null)
{
    <div class="section-header">
        <h3>Profile</h3>
        <p>Manage your personal information</p>
    </div>

    <div class="row">
        <div class="col-md-8">
            <div class="field-group">
                <label for="displayName">Display Name</label>
                <input id="displayName" class="form-control" @bind="_displayName" />
            </div>

            <div class="field-group">
                <label for="email">Email</label>
                <input id="email" type="email" class="form-control" @bind="_email" />
            </div>

            <div class="field-group">
                <label for="bio">Bio</label>
                <textarea id="bio" class="form-control" rows="4" @bind="_bio"></textarea>
            </div>
        </div>

        <div class="col-md-4">
            <div class="avatar-preview text-center">
                <img src="@_avatarUrl" alt="Avatar" class="rounded-circle mb-2" width="120" height="120" />
                <div class="field-group mt-2">
                    <label for="avatarUrl">Avatar URL</label>
                    <input id="avatarUrl" class="form-control form-control-sm" @bind="_avatarUrl" />
                </div>
            </div>
        </div>
    </div>

    <div class="btn-actions">
        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
            @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
            Save Changes
        </button>
        <button class="btn btn-outline-secondary" @onclick="Discard" disabled="@_saving">
            Discard Changes
        </button>
    </div>

    @if (_toastMessage is not null)
    {
        <div class="settings-toast">
            <div class="alert alert-success alert-dismissible mb-0" role="alert">
                @_toastMessage
                <button type="button" class="btn-close" @onclick="() => _toastMessage = null"></button>
            </div>
        </div>
    }
}

@code {
    private UserProfile? _profile;
    private string _displayName = "";
    private string _email = "";
    private string _avatarUrl = "";
    private string _bio = "";
    private bool _loading = true;
    private bool _saving;
    private string? _toastMessage;
    private CancellationTokenSource? _toastCts;

    protected override async Task OnInitializedAsync()
    {
        _profile = await SettingsService.GetProfileAsync();
        ApplyProfile(_profile);
