@code {
    private SecuritySettings? _security;
    private List<ActiveSession> _sessions = new();
    private bool _loading = true;
    private bool _twoFactorEnabled;

    // Password change
    private bool _passwordExpanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private bool _changingPassword;
    private string? _passwordError;
    private string? _passwordSuccess;

    // Session revocation
    private ActiveSession? _revokeTarget;
    private bool _revoking;

    protected override async Task OnInitializedAsync()
    {
        _security = await SettingsService.GetSecuritySettingsAsync();
        _sessions = _security.Sessions.ToList();
        _twoFactorEnabled = _security.TwoFactorEnabled;
        _loading = false;
    }

    private async Task ChangePasswordAsync()
    {
        _passwordError = null;
        _passwordSuccess = null;

        if (string.IsNullOrWhiteSpace(_currentPassword) ||
            string.IsNullOrWhiteSpace(_newPassword))
        {
            _passwordError = "Please fill in all password fields.";
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            _passwordError = "New password and confirmation do not match.";
            return;
        }

        if (_newPassword.Length < 8)
        {
            _passwordError = "New password must be at least 8 characters.";
            return;
        }

        _changingPassword = true;
        await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
        _currentPassword = "";
        _newPassword = "";
        _confirmPassword = "";
        _changingPassword = false;
        _passwordSuccess = "Password updated successfully!";
    }

    private void PromptRevoke(ActiveSession session)
    {
        _revokeTarget = session;
    }

    private void CancelRevoke()
    {
        _revokeTarget = null;
    }

    private async Task ConfirmRevokeAsync()
    {
        if (_revokeTarget is null) return;
        _revoking = true;
        await SettingsService.RevokeSessionAsync(_revokeTarget.Id);
        _sessions.RemoveAll(s => s.Id == _revokeTarget.Id);
        _revokeTarget = null;
        _revoking = false;
    }
}

