@inject ISettingsService SettingsService

@if (_loading)
{
    <div class="text-center py-5"><div class="spinner-border text-primary" role="status"></div></div>
}
else if (_security is not null)
{
    <div class="section-header">
        <h3>Security</h3>
        <p>Manage your account security</p>
    </div>

    <!-- Change Password -->
    <div class="card mb-4">
        <div class="card-header d-flex justify-content-between align-items-center"
             style="cursor: pointer;" @onclick="() => _passwordExpanded = !_passwordExpanded">
            <span class="fw-semibold">Change Password</span>
            <span>@(_passwordExpanded ? "▲" : "▼")</span>
        </div>
        @if (_passwordExpanded)
        {
            <div class="card-body">
                <div class="field-group">
                    <label for="currentPwd">Current Password</label>
                    <input id="currentPwd" type="password" class="form-control" @bind="_currentPassword" />
                </div>
                <div class="field-group">
                    <label for="newPwd">New Password</label>
                    <input id="newPwd" type="password" class="form-control" @bind="_newPassword" />
                </div>
                <div class="field-group">
                    <label for="confirmPwd">Confirm Password</label>
                    <input id="confirmPwd" type="password" class="form-control" @bind="_confirmPassword" />
                </div>
                @if (_passwordError is not null)
                {
                    <div class="alert alert-danger py-2">@_passwordError</div>
                }
                @if (_passwordSuccess is not null)
                {
                    <div class="alert alert-success py-2">@_passwordSuccess</div>
                }
                <button class="btn btn-primary" @onclick="ChangePasswordAsync" disabled="@_changingPassword">
                    @if (_changingPassword) { <span class="spinner-border spinner-border-sm me-1"></span> }
                    Update Password
                </button>
            </div>
        }
    </div>

    <!-- Two-Factor Authentication -->
    <div class="card mb-4">
        <div class="card-body d-flex justify-content-between align-items-center">
            <div>
                <h6 class="mb-1 fw-semibold">Two-Factor Authentication</h6>
                <span class="badge @(_twoFactorEnabled ? "bg-success" : "bg-secondary")">
                    @(_twoFactorEnabled ? "Enabled" : "Disabled")
                </span>
                @if (_security.LastPasswordChange.HasValue)
                {
                    <small class="text-muted ms-2">
                        Last password change: @_security.LastPasswordChange.Value.ToString("MMM dd, yyyy")
                    </small>
                }
            </div>
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" @bind="_twoFactorEnabled" />
            </div>
        </div>
    </div>

    <!-- Active Sessions -->
    <div class="card mb-4">
        <div class="card-header fw-semibold">Active Sessions</div>
        <div class="card-body p-0">
            <div class="table-responsive">
                <table class="table table-hover mb-0">
                    <thead>
                        <tr>
                            <th>Device</th>
                            <th>Location</th>
                            <th>Last Active</th>
                            <th></th>
                        </tr>
                    </thead>
                    <tbody>
                        @foreach (var session in _sessions)
                        {
                            <tr>
                                <td>
                                    @session.Device
                                    @if (session.Id == "current")
                                    {
                                        <span class="badge bg-info ms-1">Current</span>
                                    }
                                </td>
                                <td>@session.Location</td>
                                <td>@session.LastActive.ToString("MMM dd, yyyy HH:mm")</td>
                                <td>
                                    @if (session.Id != "current")
                                    {
                                        <button class="btn btn-sm btn-outline-danger"
                                                @onclick="() => PromptRevoke(session)">
                                            Revoke
                                        </button>
                                    }
                                </td>
                            </tr>
                        }
                    </tbody>
                </table>
            </div>
        </div>
    </div>

    <!-- Revoke Confirmation Modal -->
    @if (_revokeTarget is not null)
    {
        <div class="modal-backdrop show" @onclick="CancelRevoke" style="z-index: 1050;"></div>
        <div class="modal d-block" tabindex="-1" style="z-index: 1055;">
            <div class="modal-dialog modal-dialog-centered">
                <div class="modal-content">
                    <div class="modal-header">
                        <h5 class="modal-title">Revoke Session</h5>
                        <button type="button" class="btn-close" @onclick="CancelRevoke"></button>
                    </div>
                    <div class="modal-body">
                        <p>Are you sure you want to revoke the session on <strong>@_revokeTarget.Device</strong> in <strong>@_revokeTarget.Location</strong>?</p>
                        <p class="text-muted mb-0">This will sign out the device immediately.</p>
                    </div>
                    <div class="modal-footer">
                        <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                        <button class="btn btn-danger" @onclick="ConfirmRevokeAsync" disabled="@_revoking">
                            @if (_revoking) { <span class="spinner-border spinner-border-sm me-1"></span> }
                            Revoke
                        </button>
                    </div>
                </div>
            </div>
        </div>
    }
}

@code {
    private SecuritySettings? _security;
    private List<ActiveSession> _sessions = new();
    private bool _loading = true;
    private bool _twoFactorEnabled;

    // Password change
    private bool _passwordExpanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private bool _changingPassword;
    private string? _passwordError;
    private string? _passwordSuccess;

    // Session revocation
    private ActiveSession? _revokeTarget;
    private bool _revoking;

    protected override async Task OnInitializedAsync()
    {
        _security = await SettingsService.GetSecuritySettingsAsync();
        _sessions = _security.Sessions.ToList();
        _twoFactorEnabled = _security.TwoFactorEnabled;
        _loading = false;
    }

    private async Task ChangePasswordAsync()
    {
        _passwordError = null;
        _passwordSuccess = null;

        if (string.IsNullOrWhiteSpace(_currentPassword) ||
            string.IsNullOrWhiteSpace(_newPassword))
        {
            _passwordError = "Please fill in all password fields.";
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            _passwordError = "New password and confirmation do not match.";
            return;
        }

        if (_newPassword.Length < 8)
        {
            _passwordError = "New password must be at least 8 characters.";
            return;
        }

        _changingPassword = true;
        await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
        _currentPassword = "";
        _newPassword = "";
        _confirmPassword = "";
        _changingPassword = false;
        _passwordSuccess = "Password updated successfully!";
    }

    private void PromptRevoke(ActiveSession session)
    {
        _revokeTarget = session;
    }

    private void CancelRevoke()
    {
        _revokeTarget = null;
    }

    private async Task ConfirmRevokeAsync()
    {
        if (_revokeTarget is null) return;
        _revoking = true;
        await SettingsService.RevokeSessionAsync(_revokeTarget.Id);
        _sessions.RemoveAll(s => s.Id == _revokeTarget.Id);
        _revokeTarget = null;
        _revoking = false;
    }
}
