toolArgs.file_text:
@using sv_828111b90db542599b2777ad48041c1b.Services
@inject ISettingsService SettingsService

@if (_loading)
{
    <div class="text-center py-5"><div class="spinner-border text-primary" role="status"></div></div>
}
else if (_profile is not null)
{
    <div class="section-header">
        <h3>Profile</h3>
        <p>Manage your personal information</p>
    </div>

    <div class="row">
        <div class="col-md-8">
            <div class="field-group">
                <label for="displayName">Display Name</label>
                <input id="displayName" class="form-control" @bind="_displayName" />
            </div>

            <div class="field-group">
                <label for="email">Email</label>
                <input id="email" type="email" class="form-control" @bind="_email" />
            </div>

            <div class="field-group">
                <label for="bio">Bio</label>
                <textarea id="bio" class="form-control" rows="4" @bind="_bio"></textarea>
            </div>
        </div>

        <div class="col-md-4">
            <div class="avatar-preview text-center">
                <img src="@_avatarUrl" alt="Avatar" class="rounded-circle mb-2" width="120" height="120" />
                <div class="field-group mt-2">
                    <label for="avatarUrl">Avatar URL</label>
                    <input id="avatarUrl" class="form-control form-control-sm" @bind="_avatarUrl" />
                </div>
            </div>
        </div>
    </div>

    <div class="btn-actions">
        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
            @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
            Save Changes
        </button>
        <button class="btn btn-outline-secondary" @onclick="Discard" disabled="@_saving">
            Discard Changes
        </button>
    </div>

    @if (_toastMessage is not null)
    {
        <div class="settings-toast">
            <div class="alert alert-success alert-dismissible mb-0" role="alert">
                @_toastMessage
                <button type="button" class="btn-close" @onclick="() => _toastMessage = null"></button>
            </div>
        </div>
    }
}

@code {
    private UserProfile? _profile;
    private string _displayName = "";
    private string _email = "";
    private string _avatarUrl = "";
    private string _bio = "";
    private bool _loading = true;
    private bool _saving;
    private string? _toastMessage;
    private CancellationTokenSource? _toastCts;

    protected override async Task OnInitializedAsync()
    {
        _profile = await SettingsService.GetProfileAsync();
        ApplyProfile(_profile);
        _loading = false;
    }

    private void ApplyProfile(UserProfile p)
    {
        _displayName = p.DisplayName;
        _email = p.Email;
        _avatarUrl = p.AvatarUrl;
        _bio = p.Bio;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        var updated = new UserProfile(_displayName, _email, _avatarUrl, _bio);
        await SettingsService.SaveProfileAsync(updated);
        _profile = updated;
        _saving = false;
        await ShowToast("Profile saved successfully!");
    }

    private void Discard()
    {
        if (_profile is not null)
            ApplyProfile(_profile);
    }

    private async Task ShowToast(string message)
    {
        _toastCts?.Cancel();
        _toastCts = new CancellationTokenSource();
        _toastMessage = message;
        var token = _toastCts.Token;
        try
        {
            await Task.Delay(3000, token);
            _toastMessage = null;
        }
        catch (TaskCanceledException) { }
    }
}

