@using sv_828111b90db542599b2777ad48041c1b.Services
@inject ISettingsService SettingsService

@if (_loading)
{
    <div class="text-center py-5"><div class="spinner-border text-primary" role="status"></div></div>
}
else
{
    <div class="section-header">
        <h3>Notifications</h3>
        <p>Choose how you want to be notified</p>
    </div>

    <div class="mb-4">
        <h6 class="fw-semibold mb-3">Notification Channels</h6>

        <div class="form-check form-switch mb-2">
            <input class="form-check-input" type="checkbox" id="emailNotif" @bind="_emailNotifications" />
            <label class="form-check-label" for="emailNotif">Email Notifications</label>
        </div>
        <div class="form-check form-switch mb-2">
            <input class="form-check-input" type="checkbox" id="pushNotif" @bind="_pushNotifications" />
            <label class="form-check-label" for="pushNotif">Push Notifications</label>
        </div>
        <div class="form-check form-switch mb-2">
            <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="_weeklyDigest" />
            <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
        </div>
    </div>

    <div class="mb-4">
        <h6 class="fw-semibold mb-3">Muted Channels</h6>
        @foreach (var channel in MockSettingsService.AllChannels)
        {
            <div class="form-check mb-2">
                <input class="form-check-input" type="checkbox" id="ch-@channel"
                       checked="@_mutedChannels.Contains(channel)"
                       @onchange="e => ToggleMute(channel, (bool)(e.Value ?? false))" />
                <label class="form-check-label" for="ch-@channel">@channel</label>
            </div>
        }
    </div>

    <div class="btn-actions">
        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
            @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
            Save Preferences
        </button>
    </div>

    @if (_toastMessage is not null)
    {
        <div class="settings-toast">
            <div class="alert alert-success alert-dismissible mb-0" role="alert">
                @_toastMessage
                <button type="button" class="btn-close" @onclick="() => _toastMessage = null"></button>
            </div>
        </div>
    }
}

@code {
    private bool _loading = true;
    private bool _saving;
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private HashSet<string> _mutedChannels = new();
    private string? _toastMessage;
    private CancellationTokenSource? _toastCts;

    protected override async Task OnInitializedAsync()
    {
        var prefs = await SettingsService.GetNotificationPrefsAsync();
        _emailNotifications = prefs.EmailNotifications;
        _pushNotifications = prefs.PushNotifications;
        _weeklyDigest = prefs.WeeklyDigest;
        _mutedChannels = new HashSet<string>(prefs.MutedChannels);
        _loading = false;
    }

    private void ToggleMute(string channel, bool muted)
    {
        if (muted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        _saving = true;
        var prefs = new NotificationPrefs(_emailNotifications, _pushNotifications, _weeklyDigest, _mutedChannels.ToList());
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _saving = false;
        await ShowToast("Notification preferences saved!");
    }

    private async Task ShowToast(string message)
    {
        _toastCts?.Cancel();
        _toastCts = new CancellationTokenSource();
        _toastMessage = message;
        var token = _toastCts.Token;
        try { await Task.Delay(3000, token); _toastMessage = null; }
        catch (TaskCanceledException) { }
    }
}

