@using sv_828111b90db542599b2777ad48041c1b.Services
@inject ISettingsService SettingsService

@if (_loading)
{
    <div class="text-center py-5"><div class="spinner-border text-primary" role="status"></div></div>
}
else
{
    <div class="section-header">
        <h3>Appearance</h3>
        <p>Customize how the app looks and feels</p>
    </div>

    <div class="row">
        <div class="col-md-7">
            <!-- Theme -->
            <div class="mb-4">
                <h6 class="fw-semibold mb-2">Theme</h6>
                @foreach (var theme in new[] { "Light", "Dark", "System" })
                {
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="theme" id="theme-@theme"
                               value="@theme" checked="@(_theme == theme)"
                               @onchange="() => _theme = theme" />
                        <label class="form-check-label" for="theme-@theme">@theme</label>
                    </div>
                }
            </div>

            <!-- Font Size -->
            <div class="mb-4">
                <h6 class="fw-semibold mb-2">Font Size</h6>
                @foreach (var size in new[] { "Small", "Medium", "Large" })
                {
                    <div class="form-check form-check-inline">
                        <input class="form-check-input" type="radio" name="fontSize" id="fs-@size"
                               value="@size" checked="@(_fontSize == size)"
                               @onchange="() => _fontSize = size" />
                        <label class="form-check-label" for="fs-@size">@size</label>
                    </div>
                }
            </div>

            <!-- Language -->
            <div class="field-group mb-4">
                <label for="language">Language</label>
                <select id="language" class="form-select" @bind="_language">
                    <option value="English">English</option>
                    <option value="Spanish">Spanish</option>
                    <option value="French">French</option>
                    <option value="German">German</option>
                    <option value="Japanese">Japanese</option>
                    <option value="Chinese">Chinese</option>
                </select>
            </div>

            <!-- Compact Mode -->
            <div class="form-check form-switch mb-4">
                <input class="form-check-input" type="checkbox" id="compactMode" @bind="_compactMode" />
                <label class="form-check-label" for="compactMode">Compact Mode</label>
            </div>

            <div class="btn-actions">
                <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                    @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                    Save
                </button>
            </div>

            @if (_toastMessage is not null)
            {
                <div class="settings-toast">
                    <div class="alert alert-success alert-dismissible mb-0" role="alert">
                        @_toastMessage
                        <button type="button" class="btn-close" @onclick="() => _toastMessage = null"></button>
                    </div>
                </div>
            }
        </div>

        <!-- Live Preview -->
        <div class="col-md-5">
            <div class="preview-card @PreviewThemeClass" style="@PreviewFontStyle">
                <div class="preview-header">
                    <strong>Live Preview</strong>
                </div>
                <div class="preview-body" style="@(_compactMode ? "padding: 0.5rem;" : "padding: 1rem;")">
                    <p class="mb-2">This is how your content will look.</p>
                    <div class="d-flex align-items-center gap-2 mb-2">
                        <span class="badge bg-primary">Badge</span>
                        <button class="btn btn-sm btn-outline-primary">Button</button>
                    </div>
                    <ul class="mb-0" style="@(_compactMode ? "margin: 0; padding-left: 1rem;" : "")">
                        <li>Theme: @_theme</li>
                        <li>Font: @_fontSize</li>
                        <li>Language: @_language</li>
                        <li>Compact: @(_compactMode ? "On" : "Off")</li>
                    </ul>
                </div>
            </div>
        </div>
    </div>
}

@code {
    private bool _loading = true;
    private bool _saving;
    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;
    private string? _toastMessage;
    private CancellationTokenSource? _toastCts;

    private string PreviewThemeClass => _theme switch
    {
        "Dark" => "preview-dark",
        "System" => "preview-system",
        _ => "preview-light"
    };

    private string PreviewFontStyle => _fontSize switch
    {
        "Small" => "font-size: 0.8rem;",
        "Large" => "font-size: 1.15rem;",
        _ => "font-size: 0.95rem;"
    };

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetAppearanceAsync();
        _theme = settings.Theme;
        _fontSize = settings.FontSize;
        _language = settings.Language;
        _compactMode = settings.CompactMode;
        _loading = false;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        await SettingsService.SaveAppearanceAsync(new AppearanceSettings(_theme, _fontSize, _language, _compactMode));
        _saving = false;
        await ShowToast("Appearance settings saved!");
    }

    private async Task ShowToast(string message)
    {
        _toastCts?.Cancel();
        _toastCts = new CancellationTokenSource();
        _toastMessage = message;
        var token = _toastCts.Token;
        try { await Task.Delay(3000, token); _toastMessage = null; }
        catch (TaskCanceledException) { }
    }
}

.preview-card {
    border: 1px solid #dee2e6;
    border-radius: 0.5rem;
    overflow: hidden;
    transition: all 0.2s ease;
}

.preview-header {
    padding: 0.6rem 1rem;
    border-bottom: 1px solid #dee2e6;
    font-size: 0.85rem;
}

.preview-light {
    background: #ffffff;
    color: #212529;
}

.preview-light .preview-header {
    background: #f8f9fa;
}

.preview-dark {
    background: #1e1e2e;
    color: #cdd6f4;
    border-color: #45475a;
}

.preview-dark .preview-header {
    background: #181825;
    border-color: #45475a;
    color: #cdd6f4;
}

.preview-dark .badge.bg-primary {
    background-color: #89b4fa !important;
    color: #1e1e2e !important;
}

.preview-dark .btn-outline-primary {
    color: #89b4fa;
    border-color: #89b4fa;
}

.preview-system {
    background: linear-gradient(135deg, #ffffff 50%, #1e1e2e 50%);
    color: #212529;
}

.preview-system .preview-header {
    background: #e9ecef;
}

